import React, { useState, useEffect } from 'react';
import axios from 'axios';

const MicrosoftTeams = () => {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [contacts, setContacts] = useState([]);
  const [loadingContacts, setLoadingContacts] = useState(false);

  // Verificăm starea autentificării la încărcarea paginii
  useEffect(() => {
    checkAuthentication();
  }, []);

  // Funcția care verifică autentificarea
  const checkAuthentication = async () => {
    try {
      const response = await axios.get('/shortcuts/teams/auth/status/');
      setIsAuthenticated(response.data.isAuthenticated);
    } catch (error) {
      console.error('Error checking authentication:', error);
    }
  };

  // Funcție pentru redirecționarea utilizatorului la login
  const handleLogin = () => {
    window.location.href = '/shortcuts/teams/login/';  // Redirecționează utilizatorul către endpoint-ul backend pentru login
  };

  // Preia contactele utilizatorului după autentificare
  const fetchContacts = async () => {
    setLoadingContacts(true);
    try {
      const response = await axios.get('/shortcuts/teams/contacts/');
      setContacts(response.data.contacts);
    } catch (error) {
      console.error('Error fetching contacts:', error);
    } finally {
      setLoadingContacts(false);
    }
  };

  return (
    <div className="teams-container">
      <h1>Microsoft Teams</h1>
      {!isAuthenticated ? (
        <button onClick={handleLogin}>Conectare la Microsoft Teams</button>
      ) : (
        <>
          <button onClick={fetchContacts}>Preia Contactele din Microsoft Teams</button>
          {loadingContacts && <p>Se încarcă contactele...</p>}
          <ul>
            {contacts.map(contact => (
              <li key={contact.id}>{contact.displayName}</li>
            ))}
          </ul>
        </>
      )}
    </div>
  );
};

export default MicrosoftTeams;
